import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge case: simplest scenario
  it.todo("empty item list -> premium 5 G (only processing fee)");

  // Base premiums for main items
  it.todo("single sword (no modifiers, 0 years) -> base 100 + first 10 + fee 5 = 115 G");
  it.todo("single amulet (no modifiers, 0 years) -> base 60 + first 6 + fee 5 = 71 G");
  it.todo("single staff (no modifiers, 0 years) -> base 80 + first 8 + fee 5 = 93 G");
  it.todo("single potion (no modifiers, 0 years) -> base 40 + first 4 + fee 5 = 49 G");

  // Building block of 3 alike components
  it.todo("2 runes -> 50 G base premium (no block)");
  it.todo("3 runes -> 60 G base premium (block applies)");
  it.todo("4 runes -> 100 G base premium (no block, requires exactly 3)");
  it.todo("7 runes -> 175 G base premium (3+1+1+1+1 — no — 7 * 25 = 175, no block)");

  // 'Alike' components clarification
  it.todo("2 runes + 1 moonstone -> 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones -> 120 G base premium (two separate blocks)");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet (newcomer) -> 100+60 base + 50 curse + 16 first insurance + 5 fee = 231 G");

  // Modifier thresholds
  it.todo("customer with exactly 2 years -> loyalty discount applies (sword: 100 - 20 + 10 + 5 = 95 G)");
  it.todo("sword enchantment exactly 5 -> high-enchant surcharge applies (100 + 30 + 10 + 5 = 145 G)");
  it.todo("sword enchantment 5 + cursed -> both surcharges (100 + 50 + 30 + 10 + 5 = 195 G)");
  it.todo("sword enchantment 4 -> no high-enchant surcharge (100 + 10 + 5 = 115 G)");

  // Standard claim reimbursement
  it.todo("regular sword damage 500 G -> payout 400 G (500 - 100 deductible)");
  it.todo("rune (no enchantment, no material) damage 200 G -> payout 100 G");

  // Enchantment threshold vs dragon material
  it.todo("dragon-material sword enchantment 8, damage 1000 G -> payout 400 G (high-enchant 50%, then deductible)");
  it.todo("dragon-material sword enchantment 9, damage 1000 G -> payout 400 G (50% rule wins)");
  it.todo("dragon-material sword enchantment 5, damage 800 G -> payout 700 G (dragon: full minus deductible)");
  it.todo("steel sword enchantment 9, damage 1000 G -> payout 400 G (high-enchant only: 500 - 100)");

  // Deductible per damage event
  it.todo("dragon attack on sword (500 G) + amulet (300 G) -> payout 600 G (deductible per item)");

  // Multiple items of the same type
  it.todo("policy with two swords -> insurance sum 2000 G, cap 4000 G; both damaged -> separate deductibles");
  it.todo("damages contains more entries of a type than insured -> CLI non-zero exit, whole claim rejected");

  // Cap exhaustion
  it.todo("sword + amulet policy -> insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword -> cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes (block) -> insurance sum 1750 G");
  it.todo("sword (cap 2000); two claims of 1500 each -> first 1400 remaining 600; second 600 remaining 0");

  // Rounding
  it.todo("premium yielding 197.5 G -> rounded up to 198 G");
  it.todo("payout yielding 350.5 G -> rounded down to 350 G");

  // Edge cases (errors)
  it.todo("quote with unknown item type -> CLI non-zero exit, error to stderr, no results");
  it.todo("claim references item not in policy -> CLI non-zero exit, error to stderr");
  it.todo("claim with negative damage amount -> CLI non-zero exit, error to stderr");

  // Integration examples
  it.todo("newcomer cursed sword (steel, enchant 3) -> premium 165 G");
  it.todo("long-standing customer (3 years) 2nd quote, cursed sword (steel, enchant 7) -> premium 160 G");
});

export function runScenario(_input: unknown): unknown {
  throw new Error("Not implemented");
}

