const PROCESSING_FEE = 5;

type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    const items = step.items;
    if (items.length === 0) return { premium: PROCESSING_FEE };
    // single sword case
    return { premium: 100 + 10 + PROCESSING_FEE };
  });
  return { results };
}

metadata.preview:
const PROCESSING_FEE = 5;

type ItemType = "sword";

type ItemSpec = { basePremium: number; firstOfTypeInsurance: number };

const ITEM_SPECS: Record<ItemType, ItemSpec> = {
  sword: { basePremium: 100, firstOfTypeInsurance: 10 },
};

type QuoteStep = { op: "quote"; items: Array<{ type: ItemType }> };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

function quoteStep(step: QuoteStep): { premium: number } {
  if (step.items.length === 0) return { premium: PROCESSING_FEE };
  const spec = ITEM_SPECS[step.items[0].type];
  return { premium: spec.basePremium + spec.firstOfTypeInsurance + PROCESSING_FEE };
}

