const BLOCK_SIZE = 3;
const RUNE_BLOCK_PREMIUM = 60;

function calculateBasePremium(items: Array<{ type: ItemType }>): number {
  const runeCount = items.filter((i) => i.type === "rune").length;
  if (runeCount === BLOCK_SIZE) return RUNE_BLOCK_PREMIUM;
  return items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
}

