input.newString:
const BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_TYPES: ItemType[] = ["rune", "moonstone"];

function calculateBasePremiumForType(type: ItemType, count: number): number {
  if (COMPONENT_TYPES.includes(type) && count === BLOCK_SIZE) {
    return COMPONENT_BLOCK_PREMIUM;
  }
  return count * BASE_PREMIUM[type];
}

function calculateBasePremium(items: Item[]): number {
  const countsByType = new Map<ItemType, number>();
  for (const item of items) {
    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const [type, count] of countsByType) {
    total += calculateBasePremiumForType(type, count);
  }
  return total;
}

