input.newString:
function quoteStep(step: QuoteStep, customer: Customer): { premium: number } {
  const basePremium = calculateBasePremium(step.items);
  const surcharges = itemSurcharges(step.items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
  const loyaltyDiscount =
    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? basePremium * LOYALTY_RATE : 0;
  return {
    premium: roundPremiumInMHPCOFavor(
      basePremium + surcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE,
    ),
  };
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => quoteStep(step, scenario.customer));
  return { results };
}

