function claimStep(step: ClaimStep): { payout: number; remainingCap: number } {
  const totalPayout = step.incident.damages.reduce(
    (sum, dmg) => sum + Math.max(0, dmg.amount - DEDUCTIBLE),
    0,
  );
  return { payout: totalPayout, remainingCap: 0 };
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    if (step.op === "claim") return claimStep(step);
    return quoteStep(step, scenario.customer);
  });
  return { results };
}

