const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

type ItemType = "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
type Item = { type: ItemType; cursed?: boolean; enchantment?: number; material?: string };

const CURSE_RATE = 0.5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const BASE_PREMIUM: Record<ItemType, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type QuoteStep = { op: "quote"; items: Item[] };

input.oldString:
function payoutForDamage(damage: Damage): number {
  return Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
}

function claimStep(step: ClaimStep): { payout: number; remainingCap: number } {
  const payout = step.incident.damages.reduce(
    (sum, damage) => sum + payoutForDamage(damage),
    0,
  );
  return { payout, remainingCap: 0 };
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    if (step.op === "claim") return claimStep(step);
    return quoteStep(step, scenario.customer);
  });
  return { results };
}

