const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;

function reimbursableAmount(damage: Damage, item: Item): number {
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
    return damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE;
  }
  return damage.amount;
}

function payoutForDamage(damage: Damage, item: Item): number {
  return Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE_PER_DAMAGE);
}

function findItem(items: Item[], itemType: ItemType): Item | undefined {
  return items.find((i) => i.type === itemType);
}

function claimStep(
  step: ClaimStep,
  policyItems: Item[],
): { payout: number; remainingCap: number } {
  const payout = step.incident.damages.reduce((sum, damage) => {
    const item = findItem(policyItems, damage.itemType);
    if (!item) return sum;
    return sum + payoutForDamage(damage, item);
  }, 0);
  return { payout, remainingCap: 0 };
}

export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const policiesByStepIndex = new Map<number, Item[]>();
  const results = scenario.steps.map((step, index) => {
    if (step.op === "claim") {
      const items = policiesByStepIndex.get(step.policy) ?? [];
      return claimStep(step, items);
    }
    policiesByStepIndex.set(index, step.items);
    return quoteStep(step, scenario.customer);
  });
  return { results };
}

