  const scenario = input as Scenario;
  const policies = new PolicyRegistry();
  const results = scenario.steps.map((step, index) => {
    if (step.op === "claim") {
      const result = claimStep(step, policies.lookup(step.policy));
      policies.updateCap(step.policy, result.remainingCap);
      return result;
    }
    policies.register(index, createPolicy(step.items));
    return quoteStep(step, scenario.customer);
  });
  return { results };
}

input.newString:
export function runScenario(input: unknown): unknown {
  const scenario = input as Scenario;
  const policies = new PolicyRegistry();
  let quoteCount = 0;
  const results = scenario.steps.map((step, index) => {
    if (step.op === "claim") {
      const result = claimStep(step, policies.lookup(step.policy));
      policies.updateCap(step.policy, result.remainingCap);
      return result;
    }
    policies.register(index, createPolicy(step.items));
    const result = quoteStep(step, scenario.customer, quoteCount);
    quoteCount += 1;
    return result;
  });
  return { results };
}

